#[cfg(test)]
mod tests {
    use super::*;
    use std::panic;

    #[test]
    fn test_lock_recover_normal_operation() {
        let mutex = Mutex::new(42);
        let guard = lock_recover(&mutex);
        assert_eq\!(*guard, 42);
    }

    #[test]
    fn test_lock_recover_after_poison() {
        let mutex = Mutex::new(42);
        // Poison the mutex by panicking while holding lock
        let _ = panic::catch_unwind(panic::AssertUnwindSafe(|| {
            let _guard = mutex.lock().unwrap();
            panic\!("intentional panic");
        }));
        // Verify mutex is poisoned
        assert\!(mutex.lock().is_err());
        // Verify recovery works
        let guard = lock_recover(&mutex);
        assert_eq\!(*guard, 42);
    }

    #[test]
    fn test_lock_recover_debug_normal() {
        let mutex = Mutex::new("hello");
        let guard = lock_recover_debug(&mutex, "test_context");
        assert_eq\!(*guard, "hello");
    }

    #[test]
    fn test_read_recover_after_write_poison() {
        let rwlock = RwLock::new(42);
        // Poison via write
        let _ = panic::catch_unwind(panic::AssertUnwindSafe(|| {
            let _guard = rwlock.write().unwrap();
            panic\!("intentional panic");
        }));
        // Read should still recover
        let guard = read_recover(&rwlock);
        assert_eq\!(*guard, 42);
    }

    #[test]
    fn test_write_recover_after_read_poison() {
        let rwlock = RwLock::new(42);
        // Poison via read (less common but possible)
